
input[type='password']::-ms-reveal {
	display: none;
}
.login-box {
	width: 100%;
	height: 100%;
	background-position: center;
	background-repeat: no-repeat;
	background-size: 100% 100%;
	position: fixed;
	top: 0px;
	left: 0;
	display: flex;
	align-items: center;

	.login-card {
		height: 300px;
		margin: 0 auto 10vh;
		background-color: transparent;
		box-shadow: none;
		.column {
			display: flex;
			justify-content: center;
			align-items: center;
			.avatar {
				overflow: hidden;
			}
			.login-name {
				font-size: 24px;
				font-family: Roboto-Bold, Roboto;
				font-weight: bold;
				color: #ffffff;
				margin-top: 16px;
				margin-bottom: 4px;
			}
			.login-hint {
				font-size: 14px;
				font-family: Roboto-Regular, Roboto;
				font-weight: 400;
				color: #ffffff;
			}
			.login-btn {
				margin-top: 48px;
			}
		}
	}
	.item-margin {
		margin: 5px;
		width: 220px;
		height: 32px !important;
		background: rgba(255, 255, 255, 0.4);
		border-radius: 8px;
		backdrop-filter: blur(20px);
		padding-left: 12px;
		padding-right: 10px;
		display: flex;
		align-items: center;
		justify-content: space-between;
		box-sizing: border-box;
		position: relative;

		.input-wrap {
			width: 100%;
			height: 18px;
			overflow: hidden;
			display: flex;
			align-items: center;
			justify-content: flex-start;
		}

		.cursor-pointer {
			color: #ffffff;
		}

		.placeholder-label {
			position: absolute;
			left: 14px;
			top: 50%;
			transform: translateY(-50%);
			color: rgba(255, 255, 255, 0.5);
			pointer-events: none;
		}

		input {
			width: 180px;
			background-color: transparent;
			border: none;
			padding: 0;
			margin: 0;
			caret-color: #ffffff;
			letter-spacing: 1px;
			height: 28px;
			line-height: 28px;
			font-weight: 900;

			&.disable {
				pointer-events: none;
			}
			&:focus {
				outline: none;
				box-shadow: none;
			}
			&::placeholder {
				font-size: 12px;
				line-height: 20px;
			}
		}
	}
}

:global(.text-white) {
	font-size: 16px;
	font-family: Roboto-Medium, Roboto;
	font-weight: 500;
	color: #242424;
}

:global(.q-btn--rectangle) {
	border-radius: 8px;
	width: 120px;
	height: 48px;
}
:global(.q-field--standard .q-field__control:before) {
	border: none;
}
:global(.q-field--standard .q-field__control:after) {
	height: 0px;
}
