
.login-box {
	width: 100%;
	height: 100%;
	background-position: center;
	background-repeat: no-repeat;
	background-size: 100% 100%;
	position: fixed;
	top: 0px;
	left: 0;
	display: flex;
	align-items: center;

	.login-card {
		height: 300px;
		margin: 0 auto 10vh;
		background-color: transparent;
		box-shadow: none;
		.column {
			display: flex;
			justify-content: center;
			align-items: center;

			.refresh {
				width: 32px;
				height: 32px;
				border-radius: 16px;
				background: rgba(31, 24, 20, 0.3);
				margin: 0 auto;
				animation: rotate 1s linear infinite;
				position: absolute;
				left: 0;
				right: 0;
				bottom: -40px;
				margin: auto;
				overflow: hidden;
			}

			@keyframes rotate {
				0% {
					transform: rotate(0deg);
				}
				100% {
					transform: rotate(360deg);
				}
			}
		}
	}
}
