
.security {
	border-radius: 14px;
	.information-icon {
		border-radius: 60px;
		margin: 20px 0;
	}
}

.iconContainer {
	display: flex;
	align-items: center;
	justify-content: flex-start;
	border-radius: 50px;
	border: 5px solid #ffffff;
	box-sizing: border-box;
	opacity: 0.5;
	margin-bottom: 30px;
}

.second-title {
	font-weight: 600;
	font-size: 24px;
	line-height: 32px;
	color: #ffffff;
}
.second-desc {
	font-size: 14px;
	font-weight: 400;
	color: #ffffff;
	margin-bottom: 20px;
}

.mobile-size {
	width: 44px;
	height: 54px;
	font-size: 23px;
}

.pc-size {
	width: 32px;
	height: 40px;
	font-size: 20px;
}

.otp-input {
	line-height: 40px;
	margin: 0 4px;
	font-weight: 600;
	text-align: center;
	border: none;
	border-radius: 8px;
	background: rgba(255, 255, 255, 0.4);
	opacity: 1;
	color: #ffffff;

	&:focus-visible {
		border: none !important;
		padding: 0 !important;
		outline-style: none;
		outline-color: rgba(255, 255, 255, 0.4);
	}
}

.otp-input.is-complete {
	background: rgba(255, 255, 255, 0.3);
}
.otp-input::-webkit-inner-spin-button,
.otp-input::-webkit-outer-spin-button {
	-webkit-appearance: none;
	margin: 0;
}
