
.bg-container {
	width: 100%;
	height: 100%;
	position: fixed;
	left: 0;
	right: 0;
	top: 0;
	bottom: 0;
	z-index: -1;
	display: flex;
	justify-content: center;
	align-items: center;
	overflow: hidden;
}

.bg-container .desktop-bg {
	width: auto;
	min-width: 100%;
	height: 100%;
	object-fit: cover;
}
